// Generated by Spec-to-RTL pipeline: grammar -> IR -> RTL
// Repair demo setup: injected an FSM bug that forces self-loops instead of taking transitions

module fsm_handshake (
    input clk,
    input rst_n,
    input start,
    input done,
    output reg busy,
    output reg valid
);

    localparam [1:0] IDLE = 2'd0;
    localparam [1:0] RUN = 2'd1;
    localparam [1:0] DONE = 2'd2;
    reg [1:0] state_q;
    reg [1:0] next_state_q;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state_q <= IDLE;
        end else begin
            state_q <= next_state_q;
        end
    end

    always @* begin
        next_state_q = state_q;
        busy = 1'd0;
        valid = 1'd0;
        case (state_q)
            IDLE: begin
                busy = 0;
                valid = 0;
                if (start) next_state_q = RUN;
            end
            RUN: begin
                busy = 1;
                valid = 0;
                if (done) next_state_q = DONE;
            end
            DONE: begin
                busy = 0;
                valid = 1;
                next_state_q = IDLE;
            end
            default: begin
                next_state_q = IDLE;
            end
        endcase
    end

endmodule
